import { NextResponse } from 'next/server';
import { prisma } from '@/lib/db';

export const dynamic = 'force-dynamic';

export async function GET(request: Request) {
    try {
        const { searchParams } = new URL(request.url);
        const from = searchParams.get('from');
        const to = searchParams.get('to');
        const etiqueta = searchParams.get('etiqueta');
        const tipo = searchParams.get('tipo');

        const dateFilter: any = {};
        if (from) dateFilter.gte = new Date(from);
        if (to) {
            const toDate = new Date(to);
            toDate.setHours(23, 59, 59, 999);
            dateFilter.lte = toDate;
        }

        // If no dates, default to current month
        if (!from && !to) {
            const now = new Date();
            dateFilter.gte = new Date(now.getFullYear(), now.getMonth(), 1);
        }

        const whereClause: any = {
            createdAt: dateFilter,
            orderType: 'SALE',
            isDeleted: false,
        };

        const currentMonthOrders = await prisma.order.findMany({
            where: whereClause,
            select: {
                total: true,
                paid: true,
                createdAt: true,
                items: {
                    select: {
                        price: true,
                        quantity: true,
                        product: {
                            select: {
                                type: true,
                                cost: true,
                                category: true
                            }
                        }
                    }
                },
                tags: {
                    select: {
                        name: true
                    }
                },
            },
        });

        const allOrders = await prisma.order.findMany({
            where: { orderType: 'SALE', isDeleted: false },
            select: { total: true, createdAt: true },
            orderBy: { createdAt: 'asc' },
        });

        const totalSoldMonth = currentMonthOrders.reduce((acc: number, order: any) => acc + order.total, 0);
        const totalPaidMonth = currentMonthOrders.reduce((acc: number, order: any) => acc + (order.paid || 0), 0);
        const totalPendingMonth = Math.max(0, totalSoldMonth - totalPaidMonth);

        const ordersCountMonth = currentMonthOrders.length;
        const ticketPromedioMonth = ordersCountMonth > 0 ? totalSoldMonth / ordersCountMonth : 0;

        // Open Quotes (Presupuestos Activos)
        const openQuotes = await prisma.order.findMany({
            where: {
                createdAt: dateFilter,
                orderType: 'QUOTE',
                isDeleted: false,
            },
            select: { total: true }
        });
        const totalQuotesValue = openQuotes.reduce((acc, q) => acc + q.total, 0);

        // Suggested Follow-ups (Multifocal quotes > 2 days old)
        const twoDaysAgo = new Date();
        twoDaysAgo.setDate(twoDaysAgo.getDate() - 2);
        const fiveDaysAgo = new Date();
        fiveDaysAgo.setDate(fiveDaysAgo.getDate() - 7); // Don't suggest very old ones
        
        const suggestedFollowUps = await prisma.order.findMany({
            where: {
                orderType: 'QUOTE',
                isDeleted: false,
                createdAt: { lte: twoDaysAgo, gte: fiveDaysAgo },
                OR: [
                    { client: { interest: { contains: 'Multifocal' } } },
                    { items: { some: { product: { type: { contains: 'Multifocal' } } } } },
                    { items: { some: { product: { category: 'LENS' } } } }
                ]
            },
            select: {
                id: true,
                total: true,
                createdAt: true,
                client: {
                    select: {
                        name: true
                    }
                },
                items: {
                    select: {
                        product: {
                            select: {
                                brand: true,
                                model: true,
                                name: true
                            }
                        }
                    }
                }
            },
            orderBy: { createdAt: 'desc' },
            take: 5
        });

        // Monthly historical
        const monthsNames = ["Ene", "Feb", "Mar", "Abr", "May", "Jun", "Jul", "Ago", "Sep", "Oct", "Nov", "Dic"];
        const monthlyStats: Record<string, number> = {};
        const last6MonthsKeys: string[] = [];

        const now = new Date();
        for (let i = 5; i >= 0; i--) {
            const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
            const key = `${monthsNames[d.getMonth()]} ${d.getFullYear()}`;
            last6MonthsKeys.push(key);
            monthlyStats[key] = 0;
        }

        allOrders.forEach((order: any) => {
            const date = new Date(order.createdAt);
            const key = `${monthsNames[date.getMonth()]} ${date.getFullYear()}`;
            if (monthlyStats[key] !== undefined) {
                monthlyStats[key] += order.total;
            }
        });
        const tagStats: Record<string, { total: number; count: number }> = {};
        currentMonthOrders.forEach((order: any) => {
            order.tags.forEach((t: any) => {
                if (!tagStats[t.name]) tagStats[t.name] = { total: 0, count: 0 };
                tagStats[t.name].total += order.total;
                tagStats[t.name].count += 1;
            });
        });

        // Type stats
        const typeStats: Record<string, { total: number; count: number; cost: number }> = {};
        currentMonthOrders.forEach((order: any) => {
            order.items.forEach((item: any) => {
                const product = item.product;
                if (!product) return; // Skip if product was deleted

                const type = product.type || "OTROS";
                if (!typeStats[type]) typeStats[type] = { total: 0, count: 0, cost: 0 };
                typeStats[type].total += item.price * item.quantity;
                typeStats[type].count += item.quantity;
                typeStats[type].cost += (product.cost || 0) * item.quantity;
            });
        });

        // Previous period comparison
        let prevTotal = 0;
        if (from) {
            const fromDate = new Date(from);
            const toDate = to ? new Date(to) : new Date();
            const periodDays = Math.ceil((toDate.getTime() - fromDate.getTime()) / (1000 * 60 * 60 * 24));
            const prevFrom = new Date(fromDate.getTime() - periodDays * 24 * 60 * 60 * 1000);
            const prevOrders = await prisma.order.findMany({
                where: {
                    createdAt: { gte: prevFrom, lt: fromDate },
                    orderType: 'SALE',
                    isDeleted: false,
                },
                select: { total: true },
            });
            prevTotal = prevOrders.reduce((acc, o) => acc + o.total, 0);
        }

        const trendPct = prevTotal > 0 ? (((totalSoldMonth - prevTotal) / prevTotal) * 100).toFixed(1) : null;

        // ── Conversion Funnel ──
        const funnelDateFilter: any = {};
        if (from) funnelDateFilter.gte = new Date(from);
        if (to) {
            const toD = new Date(to);
            toD.setHours(23, 59, 59, 999);
            funnelDateFilter.lte = toD;
        }
        if (!from && !to) {
            const now = new Date();
            funnelDateFilter.gte = new Date(now.getFullYear(), now.getMonth(), 1);
        }

        // Build client filter for funnel
        const clientWhere: any = { createdAt: funnelDateFilter };
        if (etiqueta && etiqueta !== 'ALL') clientWhere.contactSource = etiqueta;
        if (tipo && tipo !== 'ALL') clientWhere.interest = tipo;

        // Get filtered client IDs for order counting
        const filteredClients = await prisma.client.findMany({
            where: clientWhere,
            select: { id: true },
        });
        const filteredClientIds = filteredClients.map((c: any) => c.id);

        const orderFunnelWhere: any = { createdAt: funnelDateFilter, isDeleted: false };
        if (etiqueta !== null || tipo !== null) {
            orderFunnelWhere.clientId = { in: filteredClientIds };
        }

        const [contactsCreated, quotesCreated, salesCreated] = await Promise.all([
            prisma.client.count({ where: clientWhere }),
            prisma.order.count({ where: { ...orderFunnelWhere, orderType: 'QUOTE' } }),
            prisma.order.count({ where: { ...orderFunnelWhere, orderType: 'SALE' } }),
        ]);

        // Get distinct etiquetas and tipos for filter UI
        const allClients = await prisma.client.findMany({
            select: { contactSource: true, interest: true },
        });
        const etiquetas = [...new Set(allClients.map((c: any) => c.contactSource).filter(Boolean))] as string[];
        const tipos = [...new Set(allClients.map((c: any) => c.interest).filter(Boolean))] as string[];

        const funnel = {
            contacts: contactsCreated,
            quotes: quotesCreated,
            sales: salesCreated,
            quoteRate: contactsCreated > 0 ? ((quotesCreated / contactsCreated) * 100).toFixed(1) : '0',
            saleRate: contactsCreated > 0 ? ((salesCreated / contactsCreated) * 100).toFixed(1) : '0',
            etiquetas,
            tipos,
        };

        // Monthly Targets
        const targetMonth = from ? new Date(from).getMonth() + 1 : now.getMonth() + 1;
        const targetYear = from ? new Date(from).getFullYear() : now.getFullYear();
        
        let targets = null;
        try {
            // @ts-ignore - might not be in the generated client yet
            targets = await prisma.monthlyTarget.findUnique({
                where: { month_year: { month: targetMonth, year: targetYear } }
            });
        } catch (e) {
            console.warn('Could not fetch targets, model might not be in client yet:', e);
        }

        return NextResponse.json({
            totalSoldMonth,
            ordersCountMonth,
            ticketPromedioMonth,
            trendPct,
            funnel,
            targets,
            totalPendingBalance: totalPendingMonth,
            totalQuotesValue: totalQuotesValue,
            suggestedFollowUps: suggestedFollowUps,
            monthlyBilling: last6MonthsKeys.map(key => ({ name: key, total: monthlyStats[key] })),
            tagStats: Object.entries(tagStats).map(([name, data]) => ({ name, ...data })),
            typeStats: Object.entries(typeStats).map(([name, data]) => ({ name, ...data })),
        });
    } catch (error: any) {
        console.error('Error fetching dashboard data:', error);
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}

'use client';

import { useState, useEffect } from 'react';
import {
    Wallet, Loader2, Plus, X, AlertCircle,
    ArrowUpRight, ArrowDownRight, ImageIcon,
    History, Banknote, Building2, PiggyBank, MoreHorizontal,
    CheckCircle2
} from 'lucide-react';
import { format } from 'date-fns';
import { es } from 'date-fns/locale';

// ── Types ─────────────────────────────────────

interface CashMovement {
    id: string;
    type: 'IN' | 'OUT';
    amount: number;
    reason: string;
    category: string;
    laboratory?: string | null;
    receiptUrl?: string | null;
    createdAt: string;
    user: { name: string };
}

const CATEGORIES = [
    { key: 'VENTA', label: 'Venta Entrante', icon: Wallet, color: 'text-emerald-500', bg: 'bg-emerald-50 dark:bg-emerald-950' },
    { key: 'GASTO_GENERAL', label: 'Gasto General', icon: Banknote, color: 'text-red-500', bg: 'bg-red-50 dark:bg-red-950' },
    { key: 'PAGO_LABORATORIO', label: 'Pago Laboratorio', icon: Building2, color: 'text-blue-500', bg: 'bg-blue-50 dark:bg-blue-950' },
    { key: 'APORTE_EFECTIVO', label: 'Aporte de Efectivo', icon: PiggyBank, color: 'text-emerald-500', bg: 'bg-emerald-50 dark:bg-emerald-950' },
    { key: 'OTRO', label: 'Otro', icon: MoreHorizontal, color: 'text-stone-500', bg: 'bg-stone-50 dark:bg-stone-800' },
];

const getCategoryInfo = (key: string) => CATEGORIES.find(c => c.key === key) || CATEGORIES.find(c => c.key === 'OTRO') || CATEGORIES[0];

// ── Page ──────────────────────────────────

export default function CajaPage() {
    const [movements, setMovements] = useState<CashMovement[]>([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);
    const [movementType, setMovementType] = useState<'IN' | 'OUT'>('OUT');
    const [amount, setAmount] = useState('');
    const [reason, setReason] = useState('');
    const [category, setCategory] = useState('GASTO_GENERAL');
    const [laboratory, setLaboratory] = useState('');
    const [receiptUrl, setReceiptUrl] = useState('');
    const [isSaving, setIsSaving] = useState(false);
    const [successMessage, setSuccessMessage] = useState('');
    const [viewingReceipt, setViewingReceipt] = useState<string | null>(null);

    useEffect(() => {
        fetchMovements();
    }, []);

    const fetchMovements = async () => {
        setLoading(true);
        try {
            const res = await fetch('/api/cash');
            const json = await res.json();
            if (json.movements) {
                setMovements(json.movements);
            }
        } catch (error) {
            console.error('Error fetching movements:', error);
        }
        setLoading(false);
    };

    const compressImage = (file: File): Promise<string> => {
        return new Promise((resolve) => {
            const reader = new FileReader();
            reader.readAsDataURL(file);
            reader.onload = (event) => {
                const img = new Image();
                img.src = event.target?.result as string;
                img.onload = () => {
                    const canvas = document.createElement('canvas');
                    let width = img.width;
                    let height = img.height;
                    const MAX_SIZE = 1200;
                    if (width > height) {
                        if (width > MAX_SIZE) { height *= MAX_SIZE / width; width = MAX_SIZE; }
                    } else {
                        if (height > MAX_SIZE) { width *= MAX_SIZE / height; height = MAX_SIZE; }
                    }
                    canvas.width = width;
                    canvas.height = height;
                    const ctx = canvas.getContext('2d');
                    ctx?.drawImage(img, 0, 0, width, height);
                    resolve(canvas.toDataURL('image/jpeg', 0.7));
                };
            };
        });
    };

    const handleReceiptUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        const base64 = await compressImage(file);
        setReceiptUrl(base64);
    };

    const resetForm = () => {
        setAmount('');
        setReason('');
        setCategory('GASTO_GENERAL');
        setLaboratory('');
        setReceiptUrl('');
        setMovementType('OUT');
    };

    const handleSaveMovement = async () => {
        if (!amount || !reason) return;
        setIsSaving(true);
        try {
            const userRes = await fetch('/api/auth/me');
            const userData = await userRes.json();

            const res = await fetch('/api/cash/movement', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'x-user-id': userData.id
                },
                body: JSON.stringify({
                    type: movementType,
                    amount: parseFloat(amount),
                    reason,
                    category,
                    laboratory: category === 'PAGO_LABORATORIO' ? laboratory : undefined,
                    receiptUrl: receiptUrl || undefined
                })
            });

            if (res.ok) {
                setShowModal(false);
                resetForm();
                fetchMovements();
                setSuccessMessage(movementType === 'IN' ? '✅ Ingreso registrado' : '✅ Egreso registrado');
                setTimeout(() => setSuccessMessage(''), 3000);
            }
        } catch (error) {
            console.error('Error saving movement:', error);
        } finally {
            setIsSaving(false);
        }
    };

    if (loading && movements.length === 0) {
        return (
            <main className="p-4 lg:p-8 max-w-4xl mx-auto flex items-center justify-center min-h-[60vh]">
                <div className="text-center">
                    <Loader2 className="w-10 h-10 text-primary animate-spin mx-auto mb-4" />
                    <p className="text-sm font-bold text-stone-400">Cargando caja...</p>
                </div>
            </main>
        );
    }

    return (
        <main className="p-4 lg:p-8 max-w-4xl mx-auto animate-in fade-in duration-500 pb-20">

            {/* Success Toast */}
            {successMessage && (
                <div className="fixed top-6 right-6 z-[200] bg-emerald-600 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300">
                    <CheckCircle2 size={20} />
                    <span className="text-sm font-black">{successMessage}</span>
                </div>
            )}

            {/* Header */}
            <div className="flex flex-col sm:flex-row sm:items-center justify-between mb-8 gap-4 bg-white dark:bg-stone-900 p-6 sm:p-8 rounded-[2rem] border border-stone-100 dark:border-stone-800 shadow-sm">
                <div>
                    <h1 className="text-2xl sm:text-3xl font-black text-stone-800 dark:text-white tracking-tight flex items-center gap-3">
                        <div className="w-10 h-10 bg-primary rounded-xl flex items-center justify-center text-white shadow-lg shadow-primary/20">
                            <Wallet className="w-5 h-5" />
                        </div>
                        Movimientos de Caja
                    </h1>
                    <p className="text-stone-400 text-xs mt-1.5 font-medium">
                        Registrá ingresos y egresos de efectivo
                    </p>
                </div>
            </div>

            {/* Action Buttons — Two big buttons */}
            <div className="grid grid-cols-2 gap-4 mb-8">
                <button
                    onClick={() => { setMovementType('IN'); setCategory('APORTE_EFECTIVO'); setShowModal(true); }}
                    className="group bg-white dark:bg-stone-900 border-2 border-emerald-200 dark:border-emerald-800 rounded-[2rem] p-6 sm:p-8 hover:border-emerald-400 dark:hover:border-emerald-600 transition-all hover:shadow-xl hover:shadow-emerald-100/50 dark:hover:shadow-emerald-900/20 active:scale-[0.98]"
                >
                    <div className="w-14 h-14 bg-emerald-100 dark:bg-emerald-900/30 rounded-2xl flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                        <ArrowUpRight className="w-7 h-7 text-emerald-600 dark:text-emerald-400" />
                    </div>
                    <p className="text-sm sm:text-base font-black text-stone-800 dark:text-white tracking-tight">Ingreso</p>
                    <p className="text-[10px] font-bold text-stone-400 uppercase tracking-widest mt-1">Entrada de Efectivo</p>
                </button>

                <button
