    onRefresh: () => void;
    // For Quote -> Sale conversion flow
    conversionOrderId?: string | null;
    onConversionComplete?: (rxId: string) => void;
    onCloseConversion?: () => void;
}

export default function PrescriptionManager({
    contact,
    onRefresh,
    conversionOrderId,
    onConversionComplete,
    onCloseConversion
}: PrescriptionManagerProps) {
    const [isAdding, setIsAdding] = useState(false);
    const [step, setStep] = useState<'form' | 'review'>('form');
    const [uploading, setUploading] = useState(false);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [savedRxId, setSavedRxId] = useState<string | null>(null);

    const [form, setForm] = useState({
        sphereOD: '', cylinderOD: '', axisOD: '', additionOD: '',
        sphereOI: '', cylinderOI: '', axisOI: '', additionOI: '',
        distanceOD: '', distanceOI: '', heightOD: '', heightOI: '',
        notes: '', imageUrl: '', prescriptionType: 'ADDITION'
    });

    const resetForm = () => {
        setForm({
            sphereOD: '', cylinderOD: '', axisOD: '', additionOD: '',
            sphereOI: '', cylinderOI: '', axisOI: '', additionOI: '',
            distanceOD: '', distanceOI: '', heightOD: '', heightOI: '',
            notes: '', imageUrl: '', prescriptionType: 'ADDITION'
        });
        setStep('form');
        setError(null);
    };

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        setUploading(true);
        try {
            const formData = new FormData();
            formData.append('file', file);
            const res = await fetch('/api/upload', { method: 'POST', body: formData });
            const data = await res.json();
            if (data.url) setForm(prev => ({ ...prev, imageUrl: data.url }));
        } catch (err) {
            console.error(err);
        } finally {
            setUploading(false);
        }
    };

    const applyPrevious = (rx: any) => {
        setForm({
            sphereOD: rx.sphereOD?.toString() || '',
            cylinderOD: rx.cylinderOD?.toString() || '',
            axisOD: rx.axisOD?.toString() || '',
            additionOD: (rx.additionOD ?? rx.addition)?.toString() || '',
            sphereOI: rx.sphereOI?.toString() || '',
            cylinderOI: rx.cylinderOI?.toString() || '',
            axisOI: rx.axisOI?.toString() || '',
            additionOI: (rx.additionOI ?? rx.addition)?.toString() || '',
            distanceOD: (rx.distanceOD ?? rx.pd)?.toString() || '',
            distanceOI: (rx.distanceOI ?? rx.pd)?.toString() || '',
            heightOD: rx.heightOD?.toString() || '',
            heightOI: rx.heightOI?.toString() || '',
            notes: rx.notes || '',
            imageUrl: rx.imageUrl || '',
            prescriptionType: rx.prescriptionType || 'ADDITION'
        });
    };

    const findDuplicate = () => {
        if (!contact.prescriptions) return null;

        const parse = (v: any) => {
            const n = parseFloat(v);
            return isNaN(n) ? 0 : n;
        };

        return contact.prescriptions.find((p: any) => {
            if ((p.imageUrl || '') !== (form.imageUrl || '')) return false;

            const fields = [
                [p.sphereOD, form.sphereOD], [p.cylinderOD, form.cylinderOD], [p.axisOD, form.axisOD],
                [p.sphereOI, form.sphereOI], [p.cylinderOI, form.cylinderOI], [p.axisOI, form.axisOI],
                [p.additionOD ?? p.addition, form.additionOD], [p.additionOI ?? p.addition, form.additionOI],
                [p.distanceOD ?? p.pd, form.distanceOD], [p.distanceOI ?? p.pd, form.distanceOI],
                [p.heightOD, form.heightOD], [p.heightOI, form.heightOI]
            ];

            return fields.every(([valA, valB]) => Math.abs(parse(valA) - parse(valB)) < 0.001);
        });
    };

    const handleSave = async () => {
        setSaving(true);
        setError(null);
        try {
            const duplicate = findDuplicate();
            let rxId = duplicate?.id;

            if (!rxId) {
                const res = await fetch(`/api/contacts/${contact.id}/prescriptions`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        ...form,
                        sphereOD: parseFloat(form.sphereOD) || 0,
                        cylinderOD: parseFloat(form.cylinderOD) || 0,
                        axisOD: parseInt(form.axisOD) || 0,
                        sphereOI: parseFloat(form.sphereOI) || 0,
                        cylinderOI: parseFloat(form.cylinderOI) || 0,
                        axisOI: parseInt(form.axisOI) || 0,
                        additionOD: parseFloat(form.additionOD) || 0,
                        additionOI: parseFloat(form.additionOI) || 0,
                        distanceOD: parseFloat(form.distanceOD) || 0,
                        distanceOI: parseFloat(form.distanceOI) || 0,
                        heightOD: parseFloat(form.heightOD) || 0,
                        heightOI: parseFloat(form.heightOI) || 0,
                    })
                });
                const newRx = await res.json();
                rxId = newRx.id;
            }

            if (conversionOrderId && onConversionComplete && rxId) {
                setSavedRxId(rxId);
                setStep('review');
            } else {
                onRefresh();
                setIsAdding(false);
                resetForm();
            }
        } catch (err) {
            setError('Error al guardar la receta');
        } finally {
            setSaving(false);
        }
    };

    const handleFinalConfirm = async () => {
        if (!conversionOrderId) {
            setError("No hay una orden asociada para convertir.");
            return;
        }

        const rxId = savedRxId || findDuplicate()?.id;

        if (!rxId) {
            setError("No se pudo identificar la receta. Por favor, volvé a guardarla.");
            return;
        }

        setSaving(true);
        setError(null);

        try {
            const res = await fetch(`/api/orders/${conversionOrderId}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ 
                    orderType: 'SALE',
                    prescriptionId: rxId 
                }),
            });

            const data = await res.json();

            if (!res.ok) {
                throw new Error(data.error || "Error al convertir venta");
            }

            onConversionComplete?.(rxId);
            onRefresh();
            resetForm();
        } catch (err: any) {
            console.error('Error en conversión:', err);
            setError(err.message);
        } finally {
            setSaving(false);
        }
    };

    const renderForm = () => (
        <div className="space-y-6">
            <h3 className="text-xl font-black text-stone-800 dark:text-white tracking-tighter flex items-center gap-2">
                {conversionOrderId ? 'Cargar Receta para Venta' : 'Nueva Receta'}
            </h3>

            {contact.prescriptions?.length > 0 && (
                <div className="p-4 bg-emerald-50 dark:bg-emerald-900/10 rounded-2xl border border-emerald-100 dark:border-emerald-800/50">
                    <div className="flex items-center gap-2 mb-2">
                        <History className="w-3.5 h-3.5 text-emerald-600" />
                        <span className="text-[9px] font-black text-emerald-700 uppercase tracking-widest">Usar receta anterior</span>
                    </div>
                    <div className="flex flex-wrap gap-2">
                        {contact.prescriptions.map((rx: any) => (
                            <button 
                                key={rx.id}
                                onClick={() => applyPrevious(rx)}
                                className="px-3 py-2 bg-white dark:bg-stone-900 hover:bg-emerald-500 hover:text-white border border-emerald-200 dark:border-stone-700 rounded-xl text-[10px] font-bold transition-all shadow-sm"
                            >
                                {format(new Date(rx.date), 'dd/MM/yy')} - {rx.sphereOD || '0'}/{rx.sphereOI || '0'}
                            </button>
                        ))}
                    </div>
                </div>
            )}

            <div className="grid grid-cols-1 gap-4">
                <div>
                    <p className="text-[9px] font-black text-emerald-600 uppercase tracking-widest mb-2">Ojo Derecho (OD)</p>
                    <div className="grid grid-cols-4 gap-2">
                        {['sphereOD', 'cylinderOD', 'axisOD', 'additionOD'].map(f => (
                            <div key={f}>
                                <label className="text-[8px] font-black text-stone-400 uppercase block mb-0.5">{f.replace('OD','').toUpperCase()}</label>
                                <input type="number" step="0.25" value={(form as any)[f]} onChange={e => setForm(p => ({...p, [f]: e.target.value}))} className="w-full bg-stone-50 dark:bg-stone-900 border border-stone-200 dark:border-stone-700 p-2.5 rounded-xl text-sm font-bold text-center outline-none focus:ring-2 focus:ring-emerald-300" placeholder="0.00" />
                            </div>
                        ))}
                    </div>
                </div>
                <div>
                    <p className="text-[9px] font-black text-blue-600 uppercase tracking-widest mb-2">Ojo Izquierdo (OI)</p>
                    <div className="grid grid-cols-4 gap-2">
                        {['sphereOI', 'cylinderOI', 'axisOI', 'additionOI'].map(f => (
                            <div key={f}>
                                <label className="text-[8px] font-black text-stone-400 uppercase block mb-0.5">{f.replace('OI','').toUpperCase()}</label>
                                <input type="number" step="0.25" value={(form as any)[f]} onChange={e => setForm(p => ({...p, [f]: e.target.value}))} className="w-full bg-stone-50 dark:bg-stone-900 border border-stone-200 dark:border-stone-700 p-2.5 rounded-xl text-sm font-bold text-center outline-none focus:ring-2 focus:ring-blue-300" placeholder="0.00" />
                            </div>
                        ))}
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <p className="text-[9px] font-black text-violet-600 uppercase tracking-widest mb-2">DNP</p>
                        <div className="grid grid-cols-2 gap-2">
                            <input type="number" step="0.5" value={form.distanceOD} onChange={e => setForm(p => ({...p, distanceOD: e.target.value}))} className="w-full bg-stone-50 dark:bg-stone-900 border border-stone-200 p-2.5 rounded-xl text-sm font-bold text-center" placeholder="OD" />
                            <input type="number" step="0.5" value={form.distanceOI} onChange={e => setForm(p => ({...p, distanceOI: e.target.value}))} className="w-full bg-stone-50 dark:bg-stone-900 border border-stone-200 p-2.5 rounded-xl text-sm font-bold text-center" placeholder="OI" />
                        </div>
                    </div>
                    <div>
                        <p className="text-[9px] font-black text-amber-600 uppercase tracking-widest mb-2">Altura</p>
                        <div className="grid grid-cols-2 gap-2">
                            <input type="number" step="0.5" value={form.heightOD} onChange={e => setForm(p => ({...p, heightOD: e.target.value}))} className="w-full bg-stone-50 dark:bg-stone-900 border border-stone-200 p-2.5 rounded-xl text-sm font-bold text-center" placeholder="OD" />
                            <input type="number" step="0.5" value={form.heightOI} onChange={e => setForm(p => ({...p, heightOI: e.target.value}))} className="w-full bg-stone-50 dark:bg-stone-900 border border-stone-200 p-2.5 rounded-xl text-sm font-bold text-center" placeholder="OI" />
                        </div>
                    </div>
                </div>

                <div>
                    <label className="text-[9px] font-black text-red-500 uppercase tracking-widest block mb-2">Foto de la receta (OBLIGATORIA)</label>
                    {form.imageUrl ? (
                        <div className="relative">
                            <img 
                                src={resolveStorageUrl(form.imageUrl)} 
                                alt="Receta" 
                                className="w-full max-h-48 object-contain rounded-xl border-2 border-emerald-500 shadow-md" 
                            />
                            <button onClick={() => setForm(p => ({...p, imageUrl: ''}))} className="absolute top-2 right-2 p-2 bg-red-500 text-white rounded-full"><X className="w-4 h-4" /></button>
                        </div>
                    ) : (
                        <label className="flex items-center justify-center gap-2 p-4 border-2 border-dashed border-stone-200 rounded-xl cursor-pointer hover:border-emerald-300">
                            <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
                            {uploading ? <span className="text-xs font-bold text-stone-400 animate-pulse">Subiendo...</span> : <span className="text-xs font-bold text-stone-400">Subir foto de la receta</span>}
                        </label>
                    )}
                </div>
            </div>

            {error && <p className="text-red-500 text-[10px] font-black bg-red-50 p-3 rounded-xl">⚠️ {error}</p>}

            <div className="flex gap-3">
                <button onClick={() => { setIsAdding(false); onCloseConversion?.(); resetForm(); }} className="px-6 py-4 bg-stone-100 rounded-2xl font-black text-xs uppercase tracking-widest">CANCELAR</button>
                <button 
                    onClick={handleSave} 
                    disabled={saving || (!form.sphereOD && !form.sphereOI) || !form.imageUrl}
                    className="flex-1 py-4 bg-emerald-500 text-white rounded-2xl font-black text-xs uppercase tracking-widest disabled:opacity-50"
                >
                    {saving ? 'GUARDANDO...' : 'GUARDAR RECETA'}
                </button>
            </div>
        </div>
    );

    const renderReview = () => (
        <div className="space-y-6">
            <h3 className="text-xl font-black text-stone-800 dark:text-white tracking-tighter flex items-center gap-2">Repaso Final</h3>
            <p className="text-[10px] font-bold text-stone-400">Revisá los datos antes de enviar a fábrica. Una vez confirmado, se convertirá en venta.</p>

            <div className="space-y-4">
                {['OD', 'OI'].map(eye => (
                    <div key={eye} className="flex items-center gap-3">
                        <span className="w-10 text-center font-black bg-stone-900 text-white rounded py-1 text-[10px]">{eye}</span>
                        <div className="flex-1 flex justify-around bg-stone-900 text-white p-3 rounded-2xl font-mono text-sm">
                            <div>Esf: {(form as any)[`sphere${eye}`] || '0'}</div>
                            <div>Cil: {(form as any)[`cylinder${eye}`] || '0'}</div>
                            <div>Eje: {(form as any)[`axis${eye}`] || '0'}</div>
                        </div>
                    </div>
                ))}
            </div>

            <div className="flex gap-3 mt-8">
                <button onClick={() => setStep('form')} className="px-6 py-4 bg-stone-100 rounded-2xl font-black text-xs uppercase tracking-widest">VOLVER A EDITAR</button>
                <button onClick={handleFinalConfirm} disabled={saving} className="flex-1 py-4 bg-emerald-500 text-white rounded-2xl font-black text-xs uppercase tracking-widest">CONFIRMAR Y ENVIAR A FÁBRICA</button>
            </div>
        </div>
    );

    if (conversionOrderId || isAdding) {
        return (
            <div className="fixed inset-0 bg-stone-900/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
                <div className="bg-white dark:bg-stone-800 w-full max-w-xl rounded-[2.5rem] p-8 shadow-huge max-h-[90vh] overflow-y-auto">
                    {step === 'form' ? renderForm() : renderReview()}
                </div>
            </div>
        );
    }

    return (
        <div className="animate-in fade-in duration-300">
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-2xl font-black text-stone-800 dark:text-white tracking-tighter">Registros Clínicos</h3>
                <button 
                    onClick={() => setIsAdding(true)}
                    className="flex items-center gap-2 px-6 py-3 bg-stone-900 text-white dark:bg-primary rounded-2xl font-black text-[10px] uppercase tracking-widest hover:scale-105 active:scale-95 transition-all shadow-lg"
                >
                    <Plus className="w-4 h-4" /> NUEVA RECETA
                </button>
            </div>

            <div className="grid gap-6">
                {contact.prescriptions?.map((pres: any) => (
                    <div key={pres.id} className="bg-white dark:bg-stone-800/50 border border-stone-100 dark:border-stone-800 rounded-[2rem] p-6 shadow-sm hover:shadow-md transition-all">
                        <div className="flex justify-between items-start mb-4">
                            <div className="flex items-center gap-3">
                                <div className="w-10 h-10 bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600 rounded-xl flex items-center justify-center">
                                    <FileText className="w-5 h-5" />
                                </div>
                                <div>
                                    <p className="text-xs font-black text-stone-800 dark:text-white uppercase tracking-widest">{format(new Date(pres.date), "dd 'de' MMMM", { locale: es })}</p>
                                    <p className="text-[10px] font-bold text-stone-400 italic">#{pres.id.slice(-4).toUpperCase()}</p>
                                </div>
                            </div>
                        </div>

                        <div className="mt-4">
                            <PrescriptionDetails prescription={pres} />
                        </div>
                    </div>
                ))}
            </div>

            {error && <p className="text-red-500 text-[10px] font-black bg-red-50 p-3 rounded-xl animate-shake">⚠️ {error}</p>}
        </div>
    );
}

'use client';

import React from 'react';
import { Ruler, Glasses, Activity, FileText, AlertCircle } from 'lucide-react';
import { resolveStorageUrl } from '@/lib/utils/storage';

interface PrescriptionDetailsProps {
    prescription: any;
    showEmpty?: boolean;
}

export default function PrescriptionDetails({
    prescription,
    showEmpty = true
}: PrescriptionDetailsProps) {
    if (!prescription && !showEmpty) return null;

    // Helper to format values with empty state
    const fmt = (val: any, suffix = '', prefix = '') => {
        if (val == null || val === '') return <span className="text-stone-300 dark:text-stone-700 font-bold italic text-[10px]">vacio</span>;
        return `${prefix}${val}${suffix}`;
    };

    const hasData = (val: any) => val != null && val !== '';

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            {/* 1. VISIÓN DE LEJOS / DISTANCIA */}
            <div className="bg-white dark:bg-stone-900 border border-stone-200 dark:border-stone-800 rounded-[2rem] overflow-hidden shadow-sm">
                <div className="bg-stone-900 dark:bg-stone-950 text-white text-[9px] font-black uppercase tracking-[0.2em] px-6 py-3 italic flex justify-between items-center">
                    <span>Graduación: Visión de Lejos / Distancia</span>
                    <Glasses className="w-4 h-4 opacity-50" />
                </div>

                <div className="grid grid-cols-1 divide-y divide-stone-100 dark:divide-stone-800">
                    {/* OD Row */}
                    <div className="grid grid-cols-4 sm:grid-cols-7 items-center bg-stone-50/30 dark:bg-stone-900/10">
                        <div className="px-6 py-4 bg-emerald-500/5 border-r border-stone-100 dark:border-stone-800">
                            <span className="inline-flex items-center justify-center w-8 h-8 rounded-xl bg-emerald-500 text-white text-[10px] font-black">OD</span>
                        </div>
                        {[
                            { label: 'Esfera', val: prescription?.sphereOD },
                            { label: 'Cilindro', val: prescription?.cylinderOD },
                            { label: 'Eje', val: prescription?.axisOD, suffix: '°' },
                            { label: 'Add', val: prescription?.additionOD ?? prescription?.addition, prefix: '+' },
                            { label: 'DNP', val: prescription?.distanceOD ?? prescription?.pd },
                            { label: 'Altura', val: prescription?.heightOD }
                        ].map((f, i) => (
                            <div key={i} className="px-4 py-4 text-center border-r border-stone-100 dark:border-stone-800 last:border-r-0">
                                <p className="text-[7px] font-black text-stone-400 uppercase mb-1 tracking-widest">{f.label}</p>
                                <p className={`text-sm font-black ${hasData(f.val) ? 'text-stone-800 dark:text-stone-100' : 'text-stone-300 dark:text-stone-800'}`}>
                                    {fmt(f.val, f.suffix, f.prefix)}
                                </p>
                            </div>
                        ))}
                    </div>

                    {/* OI Row */}
                    <div className="grid grid-cols-4 sm:grid-cols-7 items-center bg-white dark:bg-stone-900/5">
                        <div className="px-6 py-4 bg-blue-500/5 border-r border-stone-100 dark:border-stone-800">
                            <span className="inline-flex items-center justify-center w-8 h-8 rounded-xl bg-blue-500 text-white text-[10px] font-black">OI</span>
                        </div>
                        {[
                            { label: 'Esfera', val: prescription?.sphereOI },
                            { label: 'Cilindro', val: prescription?.cylinderOI },
                            { label: 'Eje', val: prescription?.axisOI, suffix: '°' },
                            { label: 'Add', val: prescription?.additionOI ?? prescription?.addition, prefix: '+' },
                            { label: 'DNP', val: prescription?.distanceOI ?? prescription?.pd },
                            { label: 'Altura', val: prescription?.heightOI }
                        ].map((f, i) => (
                            <div key={i} className="px-4 py-4 text-center border-r border-stone-100 dark:border-stone-800 last:border-r-0">
                                <p className="text-[7px] font-black text-stone-400 uppercase mb-1 tracking-widest">{f.label}</p>
                                <p className={`text-sm font-black ${hasData(f.val) ? 'text-stone-800 dark:text-stone-100' : 'text-stone-300 dark:text-stone-800'}`}>
                                    {fmt(f.val, f.suffix, f.prefix)}
                                </p>
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            {/* 2. VISIÓN DE CERCA / LECTURA */}
            <div className="bg-amber-50/20 dark:bg-amber-950/10 border border-amber-100 dark:border-amber-900/30 rounded-[2rem] overflow-hidden">
                <div className="bg-amber-500 text-white text-[9px] font-black uppercase tracking-[0.2em] px-6 py-2 italic flex justify-between items-center">
                    <span>Visión de Cerca / Lectura (Graduación Resultante)</span>
                    <Activity className="w-4 h-4 opacity-50" />
                </div>
                <div className="p-4 grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <div className="flex justify-between items-center p-4 bg-white/50 dark:bg-stone-900/50 rounded-2xl border border-amber-100/50">
                        <span className="text-[9px] font-black text-amber-600 dark:text-amber-500 uppercase">OD (Cerca)</span>
                        <span className="text-sm font-black text-stone-800 dark:text-stone-200">
                            {prescription?.nearSphereOD != null 
                                ? `ESF ${prescription.nearSphereOD > 0 ? '+' : ''}${prescription.nearSphereOD}`
                                : (prescription?.additionOD || prescription?.addition) > 0
                                    ? `ESF ${((prescription.sphereOD || 0) + (prescription.additionOD || prescription.addition || 0)).toFixed(2)}`
                                    : <span className="text-stone-300 italic text-[10px]">vacio</span>}
                        </span>
                    </div>
                    <div className="flex justify-between items-center p-4 bg-white/50 dark:bg-stone-900/50 rounded-2xl border border-amber-100/50">
                        <span className="text-[9px] font-black text-amber-600 dark:text-amber-500 uppercase">OI (Cerca)</span>
                        <span className="text-sm font-black text-stone-800 dark:text-stone-200">
                            {prescription?.nearSphereOI != null 
                                ? `ESF ${prescription.nearSphereOI > 0 ? '+' : ''}${prescription.nearSphereOI}`
                                : (prescription?.additionOI || prescription?.addition) > 0
                                    ? `ESF ${((prescription.sphereOI || 0) + (prescription.additionOI || prescription.addition || 0)).toFixed(2)}`
                                    : <span className="text-stone-300 italic text-[10px]">vacio</span>}
                        </span>
                    </div>
                </div>
            </div>

            {/* 3. PRISMAS Y OBSERVACIONES */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="p-5 bg-stone-50 dark:bg-stone-900/50 rounded-[2rem] border border-stone-100 dark:border-stone-800">
                    <p className="text-[9px] font-black text-stone-400 uppercase tracking-widest mb-3 flex items-center gap-2">
                        <Ruler className="w-3.5 h-3.5" /> Prismas
                    </p>
                    <div className="space-y-3">
                        <div className="flex justify-between items-center pb-2 border-b border-stone-100 dark:border-stone-800/50">
                            <span className="text-[10px] font-bold text-stone-400 uppercase">Ojo Derecho</span>
                            <span className={`text-xs font-black ${prescription?.prismOD ? 'text-stone-800 dark:text-stone-100' : 'text-stone-300 dark:text-stone-800 italic'}`}>
                                {prescription?.prismOD || 'vacio'}
                            </span>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-[10px] font-bold text-stone-400 uppercase">Ojo Izquierdo</span>
                            <span className={`text-xs font-black ${prescription?.prismOI ? 'text-stone-800 dark:text-stone-100' : 'text-stone-300 dark:text-stone-800 italic'}`}>
                                {prescription?.prismOI || 'vacio'}
                            </span>
                        </div>
                    </div>
                </div>

                <div className="p-5 bg-stone-50 dark:bg-stone-900/50 rounded-[2rem] border border-stone-100 dark:border-stone-800">
                    <p className="text-[9px] font-black text-stone-400 uppercase tracking-widest mb-2">Observaciones</p>
                    {prescription?.notes ? (
                        <p className="text-xs font-medium text-stone-600 dark:text-stone-300 italic">“{prescription.notes}”</p>
                    ) : (
                        <p className="text-[10px] text-stone-300 italic font-bold">Sin observaciones adicionales</p>
                    )}
                </div>
            </div>

            {/* Image Attachment */}
            {prescription?.imageUrl ? (
                <div className="mt-2 flex items-center gap-4 bg-emerald-50/30 dark:bg-emerald-950/20 p-4 rounded-3xl border border-emerald-100 dark:border-emerald-900/50 group cursor-pointer hover:bg-emerald-50 dark:hover:bg-emerald-950/40 transition-all" onClick={() => window.open(resolveStorageUrl(prescription.imageUrl), '_blank')}>
                    <div className="relative overflow-hidden rounded-2xl border-2 border-emerald-200">
                        <img 
                            src={resolveStorageUrl(prescription.imageUrl)} 
                            alt="Imagen de Receta" 
                            className="w-16 h-16 object-cover transition-transform group-hover:scale-110"
                        />
                    </div>
                    <div>
                        <p className="text-[9px] font-black text-emerald-600 uppercase tracking-widest flex items-center gap-1">
                            <FileText className="w-3 h-3" /> Foto Adjunta
                        </p>
                        <p className="text-[10px] font-medium text-stone-500">Haz clic para ver la receta original</p>
                    </div>
                </div>
            ) : (
                <div className="flex items-center gap-3 p-4 bg-stone-50/50 dark:bg-stone-900/20 rounded-3xl border border-dashed border-stone-200 dark:border-stone-800">
                    <AlertCircle className="w-4 h-4 text-stone-300" />
                    <span className="text-[10px] font-bold text-stone-300 uppercase tracking-widest italic">No hay imagen adjunta</span>
                </div>
            )}
        </div>
    );
}

'use client';

import React from 'react';
import { Ruler, Glasses, Activity, FileText } from 'lucide-react';

interface QuotePrescriptionProps {
    prescription: any;
}

export default function QuotePrescription({
    prescription
}: QuotePrescriptionProps) {
    if (!prescription) return null;

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            <h4 className="text-[10px] font-black text-stone-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                <FileText className="w-3.5 h-3.5" /> Receta Óptica Detallada
            </h4>

            {/* 1. VISIÓN DE LEJOS / DISTANCIA */}
            <div className="bg-stone-50/50 dark:bg-stone-900/30 border border-stone-100 dark:border-stone-800 rounded-[2rem] overflow-hidden shadow-sm">
                <div className="bg-stone-900 dark:bg-stone-950 text-white text-[9px] font-black uppercase tracking-[0.2em] px-6 py-3 italic flex justify-between items-center">
                    <span>Visión de Lejos / Distancia</span>
                    <Glasses className="w-4 h-4 opacity-50" />
                </div>

                <div className="grid grid-cols-1 divide-y divide-stone-100 dark:divide-stone-800">
                    {/* OD Row */}
                    <div className="grid grid-cols-4 sm:grid-cols-7 items-center">
                        <div className="px-6 py-4 bg-emerald-500/5 border-r border-stone-100 dark:border-stone-800">
                            <span className="inline-flex items-center justify-center w-8 h-8 rounded-xl bg-emerald-500 text-white text-[10px] font-black">OD</span>
                        </div>
                        {[
                            { label: 'Esfera', val: prescription.sphereOD },
                            { label: 'Cilindro', val: prescription.cylinderOD },
                            { label: 'Eje', val: prescription.axisOD, suffix: '°' },
                            { label: 'Add', val: prescription.additionOD ?? prescription.addition, prefix: '+' },
                            { label: 'DNP', val: prescription.distanceOD ?? prescription.pd },
                            { label: 'Altura', val: prescription.heightOD }
                        ].map((f, i) => (
                            <div key={i} className="px-4 py-4 text-center border-r border-stone-100 dark:border-stone-800 last:border-r-0">
                                <p className="text-[8px] font-black text-stone-400 uppercase mb-1">{f.label}</p>
                                <p className="text-sm font-black text-stone-800 dark:text-stone-100">
                                    {f.val != null ? `${f.prefix || ''}${f.val}${f.suffix || ''}` : '—'}
                                </p>
                            </div>
                        ))}
                    </div>

                    {/* OI Row */}
                    <div className="grid grid-cols-4 sm:grid-cols-7 items-center">
                        <div className="px-6 py-4 bg-blue-500/5 border-r border-stone-100 dark:border-stone-800">
                            <span className="inline-flex items-center justify-center w-8 h-8 rounded-xl bg-blue-500 text-white text-[10px] font-black">OI</span>
                        </div>
                        {[
                            { label: 'Esfera', val: prescription.sphereOI },
                            { label: 'Cilindro', val: prescription.cylinderOI },
                            { label: 'Eje', val: prescription.axisOI, suffix: '°' },
                            { label: 'Add', val: prescription.additionOI ?? prescription.addition, prefix: '+' },
                            { label: 'DNP', val: prescription.distanceOI ?? prescription.pd },
                            { label: 'Altura', val: prescription.heightOI }
                        ].map((f, i) => (
                            <div key={i} className="px-4 py-4 text-center border-r border-stone-100 dark:border-stone-800 last:border-r-0">
                                <p className="text-[8px] font-black text-stone-400 uppercase mb-1">{f.label}</p>
                                <p className="text-sm font-black text-stone-800 dark:text-stone-100">
                                    {f.val != null ? `${f.prefix || ''}${f.val}${f.suffix || ''}` : '—'}
                                </p>
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            {/* 2. VISIÓN DE CERCA / LECTURA (Only if has specifically near fields or it's a Near Rx) */}
            {(prescription.nearSphereOD != null || (prescription.additionOD || prescription.addition) > 0) && (
                <div className="bg-amber-50/30 dark:bg-amber-950/20 border border-amber-100 dark:border-amber-900/50 rounded-[2rem] overflow-hidden">
                    <div className="bg-amber-600 text-white text-[9px] font-black uppercase tracking-[0.2em] px-6 py-2 italic flex justify-between items-center">
                        <span>Visión de Cerca / Lectura (Graduación Resultante)</span>
                        <Activity className="w-4 h-4 opacity-50" />
                    </div>
                    <div className="p-6 grid grid-cols-1 sm:grid-cols-2 gap-6">
                        <div className="flex justify-between items-center p-4 bg-white/50 dark:bg-stone-900/50 rounded-2xl border border-amber-100/50">
                            <span className="text-[10px] font-black text-amber-700 dark:text-amber-400 uppercase">Ojo Derecho (Cerca)</span>
                            <span className="text-sm font-black text-stone-800 dark:text-stone-200">
                                {prescription.nearSphereOD != null 
                                    ? `ESF ${prescription.nearSphereOD > 0 ? '+' : ''}${prescription.nearSphereOD}`
                                    : (prescription.additionOD || prescription.addition) != null 
                                        ? `ESF ${((prescription.sphereOD || 0) + (prescription.additionOD || prescription.addition || 0)).toFixed(2)}`
                                        : '—'}
                            </span>
                        </div>
                        <div className="flex justify-between items-center p-4 bg-white/50 dark:bg-stone-900/50 rounded-2xl border border-amber-100/50">
                            <span className="text-[10px] font-black text-amber-700 dark:text-amber-400 uppercase">Ojo Izquierdo (Cerca)</span>
                            <span className="text-sm font-black text-stone-800 dark:text-stone-200">
                                {prescription.nearSphereOI != null 
                                    ? `ESF ${prescription.nearSphereOI > 0 ? '+' : ''}${prescription.nearSphereOI}`
                                    : (prescription.additionOI || prescription.addition) != null 
                                        ? `ESF ${((prescription.sphereOI || 0) + (prescription.additionOI || prescription.addition || 0)).toFixed(2)}`
                                        : '—'}
                            </span>
                        </div>
                    </div>
                </div>
            )}

            {/* 3. PRISMAS Y OTROS MEDIDAS */}
            {(prescription.prismOD || prescription.prismOI || prescription.notes) && (
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    {(prescription.prismOD || prescription.prismOI) && (
                        <div className="p-5 bg-stone-50 dark:bg-stone-900/50 rounded-[2rem] border border-stone-100 dark:border-stone-800">
                            <p className="text-[9px] font-black text-stone-400 uppercase tracking-widest mb-3 flex items-center gap-2">
